output.sparql:
PREFIX bd: <http://www.bigdata.com/rdf#>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?actor ?work ?work_label ?work_air_date WHERE {
  {
    SELECT ?series ?air_date WHERE {
      ?series wdt:P31 wd:Q1372472 .
      ?series wdt:P144 wd:Q1630304 .
      ?series wdt:P577 ?air_date .
    }
    ORDER BY ASC(?air_date)
    LIMIT 1
  }
  ?series wdt:P161 ?actor .
  {
    ?work wdt:P161 ?actor ; wdt:P31 wd:Q1372472 ; wdt:P577 ?work_air_date .
    FILTER(?work_air_date > ?air_date)
  } UNION {
    ?work wdt:P161 ?actor ; wdt:P31 wd:Q11424 ; wdt:P577 ?work_air_date .
    FILTER(?work_air_date > ?air_date)
  }
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en" .
  }
}

